import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { icon } from 'decantr/components';

code.example:
function TreeView({ data, onSelect, defaultExpanded = [] }) {
  const { div, span } = tags;
  const [expanded, setExpanded] = createSignal(new Set(defaultExpanded));
  const [selected, setSelected] = createSignal(null);

  const toggleExpand = (id) => {
    const newExpanded = new Set(expanded());
    if (newExpanded.has(id)) newExpanded.delete(id);
    else newExpanded.add(id);
    setExpanded(newExpanded);
  };

  const handleSelect = (node) => {
    setSelected(node.id);
    onSelect?.(node);
  };

  const renderNode = (node, prefix = '', isLast = true) => {
    const connector = isLast ? '└── ' : '├── ';
    const childPrefix = prefix + (isLast ? '    ' : '│   ');
    const hasChildren = node.children?.length > 0;
    const isExpanded = expanded().has(node.id);
    const isSelected = selected() === node.id;

    return [
      div({
        class: css(`_flex _aic _cursor[pointer] ${isSelected ? '_bgmuted/20' : ''} _hover:bgmuted/10`),
        onclick: () => hasChildren ? toggleExpand(node.id) : handleSelect(node)
      },
        span({ class: css('_fgmuted _whitespace[pre]') }, prefix + connector),
        hasChildren ? span({ class: css('_mr1') }, isExpanded ? '[-]' : '[+]') : null,
        icon(node.icon || (hasChildren ? 'folder' : 'file'), { size: '14', class: css('_mr1') }),
        span({ class: isSelected ? css('term-glow') : '' }, node.label)
      ),
      ...(hasChildren && isExpanded ? node.children.flatMap((child, i) =>
        renderNode(child, childPrefix, i === node.children.length - 1)
      ) : [])
    ];
  };

  return div({ class: css('term-panel _p2 _overflow[auto]') },
    ...data.flatMap((node, i) => renderNode(node, '', i === data.length - 1))
  );
}

