function FlatTree({ data, onSelect }) {
  const { div, span } = tags;

  const renderNode = (node, depth = 0) => {
    const indent = '  '.repeat(depth);
    return [
      div({ class: css('_flex _aic _cursor[pointer] _hover:bgmuted/10'), onclick: () => onSelect?.(node) },
        span({ class: css('_whitespace[pre]') }, indent),
        icon(node.icon || 'file', { size: '14', class: css('_mr1 _fgmuted') }),
        span({}, node.label)
      ),
      ...(node.children?.flatMap(child => renderNode(child, depth + 1)) || [])
    ];
  };

  return div({ class: css('term-panel _p2') }, ...data.flatMap(node => renderNode(node)));
}

