function CheckboxTree({ data, onSelectionChange }) {
  const { div, span, input } = tags;
  const [checked, setChecked] = createSignal(new Set());

  const toggleCheck = (id) => {
    const newChecked = new Set(checked());
    if (newChecked.has(id)) newChecked.delete(id);
    else newChecked.add(id);
    setChecked(newChecked);
    onSelectionChange?.(Array.from(newChecked));
  };

  const renderNode = (node, prefix = '', isLast = true) => {
    const connector = isLast ? '└── ' : '├── ';
    const childPrefix = prefix + (isLast ? '    ' : '│   ');

    return [
      div({ class: css('_flex _aic') },
        span({ class: css('_fgmuted _whitespace[pre]') }, prefix + connector),
        input({
          type: 'checkbox',
          checked: checked().has(node.id),
          onchange: () => toggleCheck(node.id),
          class: css('_mr1')
        }),
        span({}, node.label)
      ),
      ...(node.children?.flatMap((child, i) =>
        renderNode(child, childPrefix, i === node.children.length - 1)
      ) || [])
    ];
  };

  return div({ class: css('term-panel _p2') },
    ...data.flatMap((node, i) => renderNode(node, '', i === data.length - 1))
  );
}

