function TreeView({ data, variant = 'standard', ...props }) {
  switch (variant) {
    case 'flat': return FlatTree({ data, ...props });
    case 'checkbox': return CheckboxTree({ data, ...props });
    default: return StandardTreeView({ data, ...props });
  }
}
